Create the `packages/a2a-gateway/` package with project configuration files and the shared types module. This package will contain the A2A protocol handler, schema translation, Agent Card generation, and task state management.

**Implementation Steps:**

1. Create `packages/a2a-gateway/package.json`:

```json
{
  "name": "@dorkos/a2a-gateway",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "default": "./dist/index.js"
    }
  },
  "scripts": {
    "build": "tsc",
    "typecheck": "tsc --noEmit",
    "test": "vitest run",
    "lint": "eslint ."
  },
  "dependencies": {
    "@a2a-js/sdk": "0.3.13",
    "@dorkos/db": "workspace:*",
    "@dorkos/shared": "workspace:*",
    "drizzle-orm": "^0.39.0"
  },
  "devDependencies": {
    "@dorkos/eslint-config": "workspace:*",
    "@dorkos/typescript-config": "workspace:*",
    "vitest": "^4.0.18"
  }
}
```

Note: Pin `@a2a-js/sdk` to exact version `0.3.13` (no caret). Use the same vitest version as other packages in the monorepo.

2. Create `packages/a2a-gateway/tsconfig.json` (following the `@dorkos/relay` pattern):

```json
{
  "extends": "@dorkos/typescript-config/node.json",
  "compilerOptions": {
    "outDir": "./dist"
  },
  "include": ["src/**/*"],
  "exclude": ["src/**/__tests__/**"]
}
```

3. Create `packages/a2a-gateway/vitest.config.ts` (following the `@dorkos/relay` pattern):

```typescript
import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'node',
    include: ['src/**/__tests__/**/*.test.ts'],
    globals: false,
    passWithNoTests: true,
  },
});
```

4. Create `packages/a2a-gateway/src/types.ts`:

```typescript
/**
 * A2A-specific TypeScript types for the DorkOS A2A gateway.
 *
 * @module a2a-gateway/types
 */
import type { AgentCard, AgentSkill } from '@a2a-js/sdk';

/** Configuration for Agent Card generation. */
export interface CardGeneratorConfig {
  /** Base URL where the DorkOS server is accessible (e.g., "https://dorkos.example.com"). */
  baseUrl: string;
  /** DorkOS version string for the Agent Card version field. */
  version: string;
}

/** Dependencies injected into the DorkOS A2A executor. */
export interface ExecutorDeps {
  /** RelayCore instance for publishing messages to the internal bus. */
  relay: {
    publish(subject: string, payload: unknown, options: { from: string; replyTo?: string }): Promise<{ status: string }>;
    subscribe(pattern: string, handler: (envelope: unknown) => void): () => void;
  };
  /** AgentRegistry for resolving target agents. */
  agentRegistry: {
    get(id: string): { id: string; name: string; namespace?: string; capabilities: string[]; description?: string } | undefined;
    list(): Array<{ id: string; name: string; namespace?: string; capabilities: string[]; description?: string; runtime: string }>;
  };
}

/** Re-export SDK types for convenience. */
export type { AgentCard, AgentSkill };
```

5. Create `packages/a2a-gateway/src/index.ts` (initial barrel with just types):

```typescript
/**
 * @dorkos/a2a-gateway -- A2A protocol gateway for DorkOS.
 *
 * Provides Agent Card generation, schema translation between A2A and Relay,
 * SQLite-backed task persistence, and an AgentExecutor bridging A2A to Relay.
 *
 * @module a2a-gateway
 */
export type { CardGeneratorConfig, ExecutorDeps } from './types.js';
```

6. Run `pnpm install` from the repo root to link the new workspace package.

7. Verify `pnpm build --filter=@dorkos/a2a-gateway` succeeds.

**Acceptance Criteria:**
- [ ] `packages/a2a-gateway/` directory exists with `package.json`, `tsconfig.json`, `vitest.config.ts`
- [ ] `@a2a-js/sdk` is pinned to exact version `0.3.13`
- [ ] `pnpm install` succeeds from repo root
- [ ] `pnpm build --filter=@dorkos/a2a-gateway` produces `dist/` output
- [ ] `pnpm typecheck --filter=@dorkos/a2a-gateway` passes
- [ ] `src/types.ts` exports `CardGeneratorConfig` and `ExecutorDeps` interfaces

Implement `generateAgentCard()` that maps a Mesh `AgentManifest` to an A2A `AgentCard` (v0.3.0 format). Each agent capability becomes an A2A skill.

**Implementation Steps:**

1. Create `packages/a2a-gateway/src/agent-card-generator.ts`:

```typescript
/**
 * Agent Card generation from Mesh AgentManifest.
 *
 * Maps DorkOS agent manifests to A2A Agent Card format (v0.3.0)
 * for external agent discovery.
 *
 * @module a2a-gateway/agent-card-generator
 */
import type { AgentCard, AgentSkill } from '@a2a-js/sdk';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';
import type { CardGeneratorConfig } from './types.js';

/**
 * Generate a per-agent A2A Agent Card from a Mesh AgentManifest.
 *
 * Maps AgentManifest fields to A2A AgentCard fields:
 * - manifest.name -> card.name
 * - manifest.description -> card.description
 * - manifest.capabilities -> card.skills (each capability becomes a skill)
 * - manifest.id -> card.url (as /a2a/agents/:id endpoint)
 *
 * @param manifest - The agent's Mesh manifest
 * @param config - Card generation configuration (baseUrl, version)
 */
export function generateAgentCard(manifest: AgentManifest, config: CardGeneratorConfig): AgentCard {
  const skills: AgentSkill[] = manifest.capabilities.map((cap) => ({
    id: cap,
    name: cap.replace(/[-_]/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase()),
    description: `${manifest.name} capability: ${cap}`,
    tags: [cap, manifest.runtime],
    examples: [],
    inputModes: ['text/plain'],
    outputModes: ['text/plain'],
  }));

  return {
    protocolVersion: '0.3.0',
    name: manifest.name,
    description: manifest.description || `DorkOS agent: ${manifest.name}`,
    url: `${config.baseUrl}/a2a`,
    preferredTransport: 'JSONRPC',
    version: config.version,
    capabilities: {
      streaming: true,
      pushNotifications: false,
      stateTransitionHistory: true,
    },
    defaultInputModes: ['text/plain'],
    defaultOutputModes: ['text/plain'],
    skills,
    securitySchemes: {
      apiKey: {
        type: 'apiKey',
        in: 'header',
        name: 'Authorization',
      },
    },
    security: [{ apiKey: [] }],
    supportsAuthenticatedExtendedCard: false,
  };
}

/**
 * Generate a fleet-level Agent Card listing all registered agents.
 *
 * The fleet card acts as a directory -- external clients discover
 * all agents in one request, then fetch individual cards for details.
 *
 * @param manifests - All registered agent manifests from Mesh
 * @param config - Card generation configuration (baseUrl, version)
 */
export function generateFleetCard(
  manifests: AgentManifest[],
  config: CardGeneratorConfig
): AgentCard {
  const skills: AgentSkill[] = manifests.map((m) => ({
    id: m.id,
    name: m.name,
    description: m.description || `Agent: ${m.name}`,
    tags: [m.runtime, ...(m.namespace ? [m.namespace] : [])],
    examples: [],
    inputModes: ['text/plain'],
    outputModes: ['text/plain'],
  }));

  return {
    protocolVersion: '0.3.0',
    name: 'DorkOS Agent Fleet',
    description: `DorkOS instance with ${manifests.length} registered agent(s). Use per-agent cards at /a2a/agents/:id/card for individual agent details.`,
    url: `${config.baseUrl}/a2a`,
    preferredTransport: 'JSONRPC',
    version: config.version,
    capabilities: {
      streaming: true,
      pushNotifications: false,
      stateTransitionHistory: true,
    },
    defaultInputModes: ['text/plain'],
    defaultOutputModes: ['text/plain'],
    skills,
    securitySchemes: {
      apiKey: {
        type: 'apiKey',
        in: 'header',
        name: 'Authorization',
      },
    },
    security: [{ apiKey: [] }],
    supportsAuthenticatedExtendedCard: false,
  };
}
```

2. Update `packages/a2a-gateway/src/index.ts` to export the new functions:

```typescript
export type { CardGeneratorConfig, ExecutorDeps } from './types.js';
export { generateAgentCard, generateFleetCard } from './agent-card-generator.js';
```

3. Create `packages/a2a-gateway/src/__tests__/agent-card-generator.test.ts`:

```typescript
import { describe, it, expect } from 'vitest';
import { generateAgentCard, generateFleetCard } from '../agent-card-generator.js';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';
import type { CardGeneratorConfig } from '../types.js';

const config: CardGeneratorConfig = {
  baseUrl: 'https://dorkos.example.com',
  version: '0.1.0',
};

function makeManifest(overrides: Partial<AgentManifest> = {}): AgentManifest {
  return {
    id: 'agent-001',
    name: 'backend-bot',
    description: 'A backend API agent',
    runtime: 'claude-code',
    capabilities: ['code-review', 'api-design'],
    behavior: { responseMode: 'always' },
    budget: { maxHopsPerMessage: 5, maxCallsPerHour: 100 },
    namespace: 'default',
    registeredAt: '2026-03-22T00:00:00.000Z',
    registeredBy: 'user',
    personaEnabled: true,
    enabledToolGroups: {},
    ...overrides,
  };
}

describe('generateAgentCard', () => {
  it('produces a valid A2A Agent Card from a minimal AgentManifest', () => {
    const manifest = makeManifest();
    const card = generateAgentCard(manifest, config);

    expect(card.protocolVersion).toBe('0.3.0');
    expect(card.name).toBe('backend-bot');
    expect(card.description).toBe('A backend API agent');
    expect(card.url).toBe('https://dorkos.example.com/a2a');
    expect(card.version).toBe('0.1.0');
    expect(card.capabilities.streaming).toBe(true);
    expect(card.capabilities.pushNotifications).toBe(false);
  });

  it('maps capabilities to skills with proper id, name, and tags', () => {
    const manifest = makeManifest({ capabilities: ['code-review', 'api_design'] });
    const card = generateAgentCard(manifest, config);

    expect(card.skills).toHaveLength(2);
    expect(card.skills[0].id).toBe('code-review');
    expect(card.skills[0].name).toBe('Code Review');
    expect(card.skills[0].tags).toContain('code-review');
    expect(card.skills[0].tags).toContain('claude-code');
    expect(card.skills[1].id).toBe('api_design');
    expect(card.skills[1].name).toBe('Api Design');
  });

  it('handles agent with empty capabilities', () => {
    const manifest = makeManifest({ capabilities: [] });
    const card = generateAgentCard(manifest, config);

    expect(card.skills).toHaveLength(0);
  });

  it('uses fallback description when manifest description is empty', () => {
    const manifest = makeManifest({ description: '' });
    const card = generateAgentCard(manifest, config);

    expect(card.description).toBe('DorkOS agent: backend-bot');
  });

  it('includes security schemes for API key auth', () => {
    const card = generateAgentCard(makeManifest(), config);

    expect(card.securitySchemes).toBeDefined();
    expect(card.securitySchemes!.apiKey).toEqual({
      type: 'apiKey',
      in: 'header',
      name: 'Authorization',
    });
    expect(card.security).toEqual([{ apiKey: [] }]);
  });
});

describe('generateFleetCard', () => {
  it('aggregates multiple agents as skills', () => {
    const manifests = [
      makeManifest({ id: 'a1', name: 'Agent One', namespace: 'team-a' }),
      makeManifest({ id: 'a2', name: 'Agent Two', namespace: 'team-b' }),
    ];
    const card = generateFleetCard(manifests, config);

    expect(card.name).toBe('DorkOS Agent Fleet');
    expect(card.description).toContain('2 registered agent(s)');
    expect(card.skills).toHaveLength(2);
    expect(card.skills[0].id).toBe('a1');
    expect(card.skills[0].name).toBe('Agent One');
    expect(card.skills[0].tags).toContain('team-a');
    expect(card.skills[1].id).toBe('a2');
    expect(card.skills[1].tags).toContain('team-b');
  });

  it('produces valid card for empty fleet', () => {
    const card = generateFleetCard([], config);

    expect(card.skills).toHaveLength(0);
    expect(card.description).toContain('0 registered agent(s)');
  });

  it('handles agents without namespace', () => {
    const manifests = [makeManifest({ namespace: undefined })];
    const card = generateFleetCard(manifests, config);

    expect(card.skills[0].tags).toEqual(['claude-code']);
  });
});
```

**Acceptance Criteria:**
- [ ] `generateAgentCard()` maps all AgentManifest fields correctly to AgentCard
- [ ] `generateFleetCard()` aggregates multiple manifests into a single fleet card
- [ ] Capabilities are mapped to skills with human-readable names
- [ ] Empty capabilities, empty description, and missing namespace are handled gracefully
- [ ] All unit tests pass: `pnpm vitest run packages/a2a-gateway`
- [ ] `pnpm typecheck --filter=@dorkos/a2a-gateway` passes

Implement the bidirectional translation layer between A2A Messages/Tasks and Relay Envelopes/StandardPayload. This is the core adapter that converts between the two protocol formats.

**Implementation Steps:**

1. Create `packages/a2a-gateway/src/schema-translator.ts`:

```typescript
/**
 * Bidirectional translation between A2A Messages/Tasks and Relay Envelopes/StandardPayload.
 *
 * Converts inbound A2A messages to Relay format for internal routing,
 * and converts Relay responses back to A2A format for external clients.
 *
 * @module a2a-gateway/schema-translator
 */
import type { Message, Part, TaskState } from '@a2a-js/sdk';
import type { StandardPayload } from '@dorkos/shared/relay-schemas';

/**
 * Translate an inbound A2A Message to a Relay StandardPayload.
 *
 * Mapping:
 * - A2A message.parts[0].text -> StandardPayload.content
 * - A2A message.contextId -> StandardPayload.conversationId
 * - A2A message.taskId -> StandardPayload.correlationId
 * - A2A role -> StandardPayload.channelType = 'dm'
 *
 * @param message - Inbound A2A message from external client
 */
export function a2aMessageToRelayPayload(message: Message): StandardPayload {
  const textParts = message.parts
    .filter((p: Part) => p.kind === 'text')
    .map((p: Part) => (p as { kind: 'text'; text: string }).text);

  return {
    content: textParts.join('\n'),
    senderName: 'a2a-client',
    channelType: 'dm',
    conversationId: message.contextId,
    correlationId: message.taskId,
    responseContext: {
      platform: 'a2a',
      supportedFormats: ['text/plain'],
    },
    performative: 'request',
  };
}

/**
 * Translate a Relay envelope's StandardPayload into an A2A Message.
 *
 * Used when converting Relay responses back to A2A format for SSE streaming.
 *
 * @param payload - Relay StandardPayload from agent response
 * @param taskId - A2A task ID for correlation
 * @param contextId - A2A context ID for conversation threading
 */
export function relayPayloadToA2aMessage(
  payload: StandardPayload,
  taskId: string,
  contextId: string
): Message {
  return {
    kind: 'message',
    role: 'agent',
    messageId: crypto.randomUUID(),
    parts: [{ kind: 'text', text: payload.content }],
    taskId,
    contextId,
  };
}

/**
 * Map a Relay delivery status to an A2A TaskState.
 *
 * @param status - Relay delivery status from trace store
 */
export function relayStatusToTaskState(
  status: 'sent' | 'delivered' | 'failed' | 'timeout'
): TaskState {
  switch (status) {
    case 'sent':
      return 'working';
    case 'delivered':
      return 'completed';
    case 'failed':
      return 'failed';
    case 'timeout':
      return 'failed';
  }
}
```

2. Update `packages/a2a-gateway/src/index.ts` barrel to add exports:

```typescript
export { a2aMessageToRelayPayload, relayPayloadToA2aMessage, relayStatusToTaskState } from './schema-translator.js';
```

3. Create `packages/a2a-gateway/src/__tests__/schema-translator.test.ts`:

```typescript
import { describe, it, expect } from 'vitest';
import {
  a2aMessageToRelayPayload,
  relayPayloadToA2aMessage,
  relayStatusToTaskState,
} from '../schema-translator.js';
import type { Message } from '@a2a-js/sdk';
import type { StandardPayload } from '@dorkos/shared/relay-schemas';

describe('a2aMessageToRelayPayload', () => {
  it('maps text parts to StandardPayload.content', () => {
    const message: Message = {
      kind: 'message',
      role: 'user',
      messageId: 'msg-1',
      parts: [{ kind: 'text', text: 'Hello agent' }],
      taskId: 'task-1',
      contextId: 'ctx-1',
    };

    const payload = a2aMessageToRelayPayload(message);

    expect(payload.content).toBe('Hello agent');
    expect(payload.senderName).toBe('a2a-client');
    expect(payload.channelType).toBe('dm');
    expect(payload.conversationId).toBe('ctx-1');
    expect(payload.correlationId).toBe('task-1');
    expect(payload.performative).toBe('request');
    expect(payload.responseContext?.platform).toBe('a2a');
  });

  it('concatenates multiple text parts with newline', () => {
    const message: Message = {
      kind: 'message',
      role: 'user',
      messageId: 'msg-2',
      parts: [
        { kind: 'text', text: 'Line 1' },
        { kind: 'text', text: 'Line 2' },
      ],
      taskId: 'task-2',
      contextId: 'ctx-2',
    };

    const payload = a2aMessageToRelayPayload(message);
    expect(payload.content).toBe('Line 1\nLine 2');
  });

  it('handles messages with no text parts', () => {
    const message: Message = {
      kind: 'message',
      role: 'user',
      messageId: 'msg-3',
      parts: [],
      taskId: 'task-3',
      contextId: 'ctx-3',
    };

    const payload = a2aMessageToRelayPayload(message);
    expect(payload.content).toBe('');
  });
});

describe('relayPayloadToA2aMessage', () => {
  it('creates proper A2A Message with text parts', () => {
    const payload: StandardPayload = {
      content: 'Agent response here',
      senderName: 'backend-bot',
    };

    const message = relayPayloadToA2aMessage(payload, 'task-1', 'ctx-1');

    expect(message.kind).toBe('message');
    expect(message.role).toBe('agent');
    expect(message.parts).toHaveLength(1);
    expect(message.parts[0]).toEqual({ kind: 'text', text: 'Agent response here' });
    expect(message.taskId).toBe('task-1');
    expect(message.contextId).toBe('ctx-1');
    expect(message.messageId).toBeDefined();
  });
});

describe('relayStatusToTaskState', () => {
  it('maps sent to working', () => {
    expect(relayStatusToTaskState('sent')).toBe('working');
  });

  it('maps delivered to completed', () => {
    expect(relayStatusToTaskState('delivered')).toBe('completed');
  });

  it('maps failed to failed', () => {
    expect(relayStatusToTaskState('failed')).toBe('failed');
  });

  it('maps timeout to failed', () => {
    expect(relayStatusToTaskState('timeout')).toBe('failed');
  });
});
```

**Acceptance Criteria:**
- [ ] `a2aMessageToRelayPayload()` correctly maps A2A text parts to StandardPayload content
- [ ] `relayPayloadToA2aMessage()` creates valid A2A Messages with role 'agent'
- [ ] `relayStatusToTaskState()` maps all four Relay statuses correctly
- [ ] Multi-part messages concatenate text with newlines
- [ ] All unit tests pass: `pnpm vitest run packages/a2a-gateway`

Implement `SqliteTaskStore` that satisfies the `@a2a-js/sdk` `TaskStore` interface, backed by the `a2a_tasks` Drizzle table. This enables task state persistence across server restarts and supports task history queries.

**Implementation Steps:**

1. Create `packages/a2a-gateway/src/task-store.ts`:

```typescript
/**
 * SQLite-backed TaskStore for A2A task persistence.
 *
 * Implements the @a2a-js/sdk TaskStore interface using Drizzle ORM
 * against the a2a_tasks table. Survives server restarts and enables
 * task history queries.
 *
 * @module a2a-gateway/task-store
 */
import type { Task, TaskStore, TaskQueryParams } from '@a2a-js/sdk';
import { eq } from 'drizzle-orm';
import type { Db } from '@dorkos/db';
import { a2aTasks } from '@dorkos/db/schema';

/** SQLite-backed TaskStore for A2A task persistence. */
export class SqliteTaskStore implements TaskStore {
  constructor(private readonly db: Db) {}

  /** Retrieve a task by ID. Returns null if not found. */
  async get(params: TaskQueryParams): Promise<Task | null> {
    const row = this.db.select().from(a2aTasks).where(eq(a2aTasks.id, params.id)).get();
    return row ? this.rowToTask(row) : null;
  }

  /** Persist a task (insert or update). Uses upsert for idempotency. */
  async save(task: Task): Promise<void> {
    const now = new Date().toISOString();
    this.db
      .insert(a2aTasks)
      .values({
        id: task.id,
        contextId: task.contextId,
        agentId: this.extractAgentId(task),
        status: task.status.state,
        historyJson: JSON.stringify(task.history ?? []),
        artifactsJson: JSON.stringify(task.artifacts ?? []),
        metadataJson: task.metadata ? JSON.stringify(task.metadata) : null,
        createdAt: now,
        updatedAt: now,
      })
      .onConflictDoUpdate({
        target: a2aTasks.id,
        set: {
          status: task.status.state,
          historyJson: JSON.stringify(task.history ?? []),
          artifactsJson: JSON.stringify(task.artifacts ?? []),
          metadataJson: task.metadata ? JSON.stringify(task.metadata) : null,
          updatedAt: now,
        },
      })
      .run();
  }

  /** Convert a database row to an A2A Task object. */
  private rowToTask(row: typeof a2aTasks.$inferSelect): Task {
    return {
      kind: 'task',
      id: row.id,
      contextId: row.contextId,
      status: {
        state: row.status as Task['status']['state'],
        timestamp: row.updatedAt,
      },
      history: JSON.parse(row.historyJson),
      artifacts: JSON.parse(row.artifactsJson),
      metadata: row.metadataJson ? JSON.parse(row.metadataJson) : undefined,
    };
  }

  /** Extract agent ID from task metadata, defaulting to 'unknown'. */
  private extractAgentId(task: Task): string {
    return (task.metadata as Record<string, string>)?.agentId ?? 'unknown';
  }
}
```

2. Update barrel `packages/a2a-gateway/src/index.ts`:

```typescript
export { SqliteTaskStore } from './task-store.js';
```

3. Create `packages/a2a-gateway/src/__tests__/task-store.test.ts`:

```typescript
import { describe, it, expect, beforeEach } from 'vitest';
import { createDb, runMigrations } from '@dorkos/db';
import type { Db } from '@dorkos/db';
import type { Task } from '@a2a-js/sdk';
import { SqliteTaskStore } from '../task-store.js';

let db: Db;
let store: SqliteTaskStore;

function makeTask(overrides: Partial<Task> = {}): Task {
  return {
    kind: 'task',
    id: 'task-001',
    contextId: 'ctx-001',
    status: { state: 'submitted', timestamp: '2026-03-22T00:00:00.000Z' },
    history: [],
    artifacts: [],
    metadata: { agentId: 'agent-001' },
    ...overrides,
  };
}

beforeEach(() => {
  db = createDb(':memory:');
  runMigrations(db);
  store = new SqliteTaskStore(db);
});

describe('SqliteTaskStore', () => {
  it('saves and retrieves a task by ID', async () => {
    const task = makeTask();
    await store.save(task);

    const retrieved = await store.get({ id: 'task-001' });
    expect(retrieved).not.toBeNull();
    expect(retrieved!.id).toBe('task-001');
    expect(retrieved!.contextId).toBe('ctx-001');
    expect(retrieved!.status.state).toBe('submitted');
  });

  it('returns null for non-existent task', async () => {
    const result = await store.get({ id: 'nonexistent' });
    expect(result).toBeNull();
  });

  it('upserts: save twice updates the existing row', async () => {
    const task = makeTask();
    await store.save(task);

    const updated = makeTask({
      status: { state: 'completed', timestamp: '2026-03-22T01:00:00.000Z' },
      history: [{ kind: 'message', role: 'agent', messageId: 'm1', parts: [{ kind: 'text', text: 'Done' }], taskId: 'task-001', contextId: 'ctx-001' }],
    });
    await store.save(updated);

    const retrieved = await store.get({ id: 'task-001' });
    expect(retrieved!.status.state).toBe('completed');
    expect(retrieved!.history).toHaveLength(1);
  });

  it('serializes and deserializes history JSON correctly', async () => {
